#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int P[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &P[i]);
        }
        qsort(P, N, sizeof(int), compare);
        long long dp[N + 1][K + 1] = {0};
        dp[0][0] = 1;
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                for (int k = 0; k <= j; k++) {
                    if (k == 0 || (i > 1 && P[i - 1] > P[i - 2])) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                    }
                }
            }
        }
        long long ans = 0;
        for (int i = 0; i <= K; i++) {
            ans = (ans + dp[N][i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

