        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] P = new int[N];
            for (int i = 0; i < N; i++) {
                P[i] = sc.nextInt();
            }
            Arrays.sort(P);
            long[][] dp = new long[N + 1][K + 1];
            dp[0][0] = 1;
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    for (int k = 0; k <= j; k++) {
                        if (k == 0 || (i > 1 && P[i - 1] > P[i - 2])) {
                            dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                        }
                    }
